import (
	"container/heap"
	"math"
)

func solve(grid [][]int64, k int64) int64 {
	m := len(grid)
	n := len(grid[0])

	// Precompute teleport lists
	teleportList := make([][][2]int, m)
	for i := 0; i < m; i++ {
		teleportList[i] = make([][2]int, n)
		for j := 0; j < n; j++ {
			for x := 0; x < m; x++ {
				for y := 0; y < n; y++ {
					if grid[x][y] <= grid[i][j] {
						teleportList[i][j] = append(teleportList[i][j], [2]int{x, y})
					}
				}
			}
		}
	}

	// Initialize distance array
	dist := make([][][]int64, m)
	for i := 0; i < m; i++ {
		dist[i] = make([][]int64, n)
		for j := 0; j < n; j++ {
			dist[i][j] = make([]int64, k+1)
			for t := 0; t <= int(k); t++ {
				dist[i][j][t] = math.MaxInt64
			}
		}
	}

	// Dijkstra's algorithm
	type State struct {
		cost int64
		i    int
		j    int
		t    int
	}

	// Priority queue
	pq := make([]State, 0)
	heap.Init(&pq)
	dist[0][0][0] = 0
	heap.Push(&pq, State{cost: 0, i: 0, j: 0, t: 0})

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(*State)
		currentCost := current.cost
		i, j, t := current.i, current.j, current.t

		// Check if we reached the destination
		if i == m-1 && j == n-1 {
			return currentCost
		}

		// Regular moves: right and down
		// Right move
		if j+1 < n {
			newCost := currentCost + grid[i][j+1]
			if newCost < dist[i][j+1][t] {
				dist[i][j+1][t] = newCost
				heap.Push(&pq, State{cost: newCost, i: i, j: j + 1, t: t})
			}
		}
		// Down move
		if i+1 < m {
			newCost := currentCost + grid[i+1][j]
			if newCost < dist[i+1][j][t] {
				dist[i+1][j][t] = newCost
				heap.Push(&pq, State{cost: newCost, i: i + 1, j: j, t: t})
			}
		}

		// Teleportation
		if t < int(k) {
			for _, coord := range teleportList[i][j] {
				x, y := coord[0], coord[1]
				if currentCost < dist[x][y][t+1] {
					dist[x][y][t+1] = currentCost
					heap.Push(&pq, State{cost: currentCost, i: x, j: y, t: t + 1})
				}
			}
		}
	}

	// If not found (should not happen)
	return -1
}
