import (
	"container/heap"
	"math"
)

type State struct {
	cost int64
	i, j, t int
}

type PQ []*State

func (h PQ) Len() int { return len(h) }
func (h PQ) Less(i, j int) bool { return h[i].cost < h[j].cost }
func (h PQ) Swap(i, j int) { h[i], h[j] = h[j], h[i] }
func (h *PQ) Push(x interface{}) {
	item := x.(*State)
	*h = append(*h, item)
}
func (h *PQ) Pop() interface{} {
	old := *h
	n := len(old)
	item := old[n-1]
	*h = old[0 : n-1]
	return item
}

func solve(grid [][]int64, k int64) int64 {
	m := len(grid)
	n := len(grid[0])
	if m == 0 || n == 0 {
		return 0
	}

	// Precompute teleport list
	teleportList := make([][][]struct{ x, y int }, m)
	for i := 0; i < m; i++ {
		teleportList[i] = make([][]struct{ x, y int }, n)
		for j := 0; j < n; j++ {
			teleportList[i][j] = make([]struct{ x, y int }, 0)
			for x := 0; x < m; x++ {
				for y := 0; y < n; y++ {
					if grid[x][y] <= grid[i][j] {
						teleportList[i][j] = append(teleportList[i][j], struct{ x, y int }{x, y})
					}
				}
			}
		}
	}

	// Initialize distance array
	dist := make([][][]int64, m)
	for i := 0; i < m; i++ {
		dist[i] = make([][]int64, n)
		for j := 0; j < n; j++ {
			dist[i][j] = make([]int64, k+1)
			for t := 0; t <= int(k); t++ {
				dist[i][j][t] = math.MaxInt64
			}
		}
	}

	// Dijkstra's algorithm
	pq := make(PQ, 0)
	heap.Init(&pq)
	initialCost := int64(0)
	dist[0][0][0] = initialCost
	heap.Push(&pq, &State{cost: initialCost, i: 0, j: 0, t: 0})

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(*State)
		currentCost := current.cost
		i, j, t := current.i, current.j, current.t

		// Check if destination
